let iterations = 0;
let lastCallKey = null;
while (true) {
  if (++iterations > 20) { console.warn('Max iterations reached'); break; }
  const response = await client.messages.create({...});
  if (response.stop_reason === 'end_turn') return response.content[0].text;
  const toolCall = response.content.find(b => b.type === 'tool_use');
  const callKey = `${toolCall.name}:${JSON.stringify(toolCall.input)}`;
  if (callKey === lastCallKey) { console.warn('Repetition detected, stopping'); break; }
  lastCallKey = callKey;
  console.log(`[${iterations}] ${toolCall.name}`, JSON.stringify(toolCall.input).slice(0,100));
  const result = await executeTool(toolCall.name, toolCall.input);
  messages.push({ role: 'assistant', content: response.content });
  messages.push({ role: 'user', content: [{ type: 'tool_result', tool_use_id: toolCall.id, content: result }] });
}
